class Solution:
    def maximumProduct(self, nums, k):
        arr = list(nums)
        for _ in range(k):
            min_idx = 0
            for i in range(1, len(arr)):
                if arr[i] < arr[min_idx]:
                    min_idx = i
            arr[min_idx] += 1
        MOD = 10 ** 9 + 7
        product = 1
        for v in arr:
            product = (product * v) % MOD
        return product

