import heapq

class Solution:
    def maximumProduct(self, nums, k):
        heap = list(nums)
        heapq.heapify(heap)
        for _ in range(k):
            smallest = heapq.heappop(heap)
            heapq.heappush(heap, smallest + 1)
        MOD = 10 ** 9 + 7
        product = 1
        for v in heap:
            product = (product * v) % MOD
        return product

